// Generic TLDs that carry no country signal
const genericTLDs = new Set([
  'com','net','org','edu','gov','mil','int','info','biz','name','pro',
  'aero','coop','museum','io','co','ai','app','dev','tech','online',
  'site','web','shop','store','cloud','digital','global','world',
  'media','agency','studio','group','team','solutions','services',
  'consulting','management','finance','health','legal','law',
]);

const data = $('Prepare Company Data').item.json;
const domain = data.domain || '';

let countryFromTLD = '';
let tldUsed = '';

if (domain) {
  const parts = domain.toLowerCase().replace(/^www\./, '').split('.');
  // Check second-level country TLDs first (e.g. co.uk, com.au, org.uk)
  if (parts.length >= 3) {
    const secondLevel = parts[parts.length - 2];
    const tld = parts[parts.length - 1];
    if (['co','com','org','net','gov','ac','me','ne'].includes(secondLevel) && tldToCountry[tld]) {
      countryFromTLD = tldToCountry[tld];
      tldUsed = secondLevel + '.' + tld;
    }
  }
  // Check simple TLD
  if (!countryFromTLD && parts.length >= 2) {
    const tld = parts[parts.length - 1];
    if (!genericTLDs.has(tld) && tldToCountry[tld]) {
      countryFromTLD = tldToCountry[tld];
      tldUsed = tld;
    }
  }
}

return {
  json: {
    ...data,
    countryFromTLD,
    tldUsed,
  }
};

const data = $json;
const companyData = $('Prepare Company Data').item.json;

// Find primary location, fall back to first location
const locations = data.locations || [];
const primary = locations.find(l => l.is_primary) || locations[0] || {};
const countryFromAmplemarket = primary.country || '';

return {
  json: {
    ...companyData,
    countryFromAmplemarket,
  }
};

const companyData = $('Prepare Company Data').item.json;
const websiteContent = ($('Website Scraping').item.json.data || '')
  .replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '$2')  // keep image URLs, drop alt text
  .replace(/\[([^\]]*)\]\(([^)]+)\)/g, '$1 $2') // keep both link text and URL
  .replace(/\n{3,}/g, '\n\n')
  .trim()
  .substring(0, 6000);

const prompt = `You are an expert at identifying the headquarters country of a company from its website content.

COMPANY: ${companyData.companyName}
DOMAIN: ${companyData.domain}

WEBSITE CONTENT:
${websiteContent || 'Not available'}

TASK: Identify the single country where this company's headquarters is located.

SIGNAL PRIORITY (apply in this order):
1. Physical address or registered office explicitly mentioned on the page
2. Phone number country code or local format (e.g. +49 = Germany, +44 = UK)
3. VAT number format, company registration number format
4. CDN or storage URLs containing region hints (e.g. s3-eu-west-1 = Ireland, s3.ap-southeast-1 = Singapore)
5. Language of the website content (weakest signal — only use if nothing else found)

RULES:
- Return ONLY the full country name in English (e.g. "Germany", "United Kingdom", "United States")
- If the company operates in multiple countries, return the headquarters country only
- If you cannot determine the country with reasonable confidence, return exactly: UNKNOWN
- No explanation, no punctuation, just the country name or UNKNOWN

Your response:`;

return {
  json: {
    companyId: companyData.companyId,
    companyName: companyData.companyName,
    domain: companyData.domain,
    linkedinUrl: companyData.linkedinUrl,
    prompt
  }
};

const geminiText = ($json?.candidates?.[0]?.content?.parts?.[0]?.text || '').trim();
const companyData = $('Prepare Company Data').item.json;

const countryFromGemini = (geminiText && geminiText !== 'UNKNOWN') ? geminiText : '';

return {
  json: {
    companyId: companyData.companyId,
    companyName: companyData.companyName,
    domain: companyData.domain,
    linkedinUrl: companyData.linkedinUrl,
    countryFromGemini,
  }
};

const d = $input.item.json;
const country = d.countryFromTLD || d.countryFromName || d.countryFromAmplemarket || d.countryFromAmplemarketDomain || d.countryFromGemini || '';

let enrichmentSource = '';
if (d.countryFromTLD)                    enrichmentSource = 'Domain code';
else if (d.countryFromName)              enrichmentSource = 'Company name';
else if (d.countryFromAmplemarket)       enrichmentSource = 'Linkedin';
else if (d.countryFromAmplemarketDomain) enrichmentSource = 'Amplemarket domain';
else if (d.countryFromGemini)            enrichmentSource = 'Website';

return {
  json: {
    companyId: d.companyId,
    companyName: d.companyName,
    country,
    enrichmentSource,
    resolved: true,
  }
};

const d = $input.item.json;
return {
  json: {
    companyId: d.companyId,
    companyName: d.companyName,
    country: '',
    enrichmentSource: 'Manual review',
    resolved: false,
  }
};

const d = $input.item.json;
return {
  json: {
    companyId: d.companyId,
    companyName: d.companyName,
    country: d.country,
    enrichmentSource: d.enrichmentSource,
    resolved: d.resolved,
  }
};

const items = $json.data || [];
const resolved = items.filter(i => i.resolved);
const manual   = items.filter(i => !i.resolved);

const hubspotBase = 'https://app.hubspot.com/contacts/142047914/company/';

let msg = `🌍 *Country Retroactive Enrichment — Run Complete*\n`;
msg += `*${resolved.length} classified · ${manual.length} need manual review*\n\n`;

if (resolved.length > 0) {
  msg += `✅ *Classified*\n`;
  for (const c of resolved) {
    const url = hubspotBase + c.companyId;
    msg += `• <${url}|${c.companyName}> → *${c.country}* (${c.enrichmentSource})\n`;
  }
}

if (manual.length > 0) {
  msg += `\n🚩 *Needs Manual Review*\n`;
  for (const c of manual) {
    const url = hubspotBase + c.companyId;
    msg += `• <${url}|${c.companyName}>\n`;
  }
}

return { json: { message: msg } };

