const data = $('Prepare Company Data').item.json;
const name = (data.companyName || '').toLowerCase();
let countryFromName = '';

for (const c of countries) {
  if (name.includes(c.toLowerCase())) {
    countryFromName = c;
    break;
  }
}

return { json: { ...data, countryFromName } };

const content = $json.data || '';
const companyData = $('Prepare Company Data').item.json;

const match = content.match(/https?:\/\/(?:www\.)?linkedin\.com\/company\/[a-zA-Z0-9_%-]+(?:\/[a-zA-Z0-9_%-]*)*/i);
const raw = match ? match[0] : '';

// Reject numeric-only IDs (e.g. /company/68697181) — Amplemarket needs slugs
const slug = raw.split('/company/')[1]?.split('/')[0] || '';
const linkedinFromWebsite = /^\d+$/.test(slug) ? '' : raw;

return {
  json: {
    ...companyData,
    linkedinUrl: linkedinFromWebsite || companyData.linkedinUrl,
    linkedinFromWebsite,
  }
};

